import "./styles/StudentDashboard.css";

const historyData = {
  Fantasy: ["Harry Potter", "The Hobbit", "Percy Jackson"],
  Technology: ["Clean Code", "Refactoring"],
  Business: ["Zero to One"],
  Literature: ["Hamlet", "Jane Eyre"]
};

function StudentDashboard() {
  return (
    <div className="student-dashboard">

      <h1 className="dash-title">Welcome back, Reader ✨</h1>
      <p className="dash-sub">Your BookSphere journey so far</p>

      <div className="history-section">
        <h2>📊 Reading History by Category</h2>

        <div className="history-grid">
          {Object.entries(historyData).map(([category, books], i) => (
            <div key={i} className="history-card">

              <h3>{category}</h3>
              <p>{books.length} Books Read</p>

              <div className="progress-bar">
                <div
                  className="progress-fill"
                  style={{ width: `${books.length * 10}%` }}
                ></div>
              </div>

              <ul>
                {books.map((b, j) => (
                  <li key={j}>{b}</li>
                ))}
              </ul>

            </div>
          ))}
        </div>
      </div>

    </div>
  );
}

export default StudentDashboard;
